documentation:
query ($query: String) {
  Page(perPage: 50) {
    pageInfo {
      total
      currentPage
      hasNextPage
    }
    media(search: $query, type: ANIME) {
      id
      idMal
      title {
        romaji
        english
      }
      episodes
      status
      nextAiringEpisode {
        timeUntilAiring
        airingAt
        episode
      }
    }
  }
}
